const finalResults = [];

// Проходим по ВСЕМ элементам в массиве
for (const item of items) {
    const currentItem = item.json || item;

    // --- ИЗВЛЕЧЕНИЕ ДАННЫХ И ЦЕНЫ ПРОДАЖИ ---
    const currentSpread = Number(currentItem.spread); 
    const currentVolume = Number(currentItem.volume) || 0; 
    const feeInCoin = Number(currentItem.fee) || 0; 

    // !!! ИЗВЛЕЧЕНИЕ ЦЕНЫ ПРОДАЖИ (Sell Price) !!!
    const sellPriceUSDT = Number(currentItem.sell_price) || Number(currentItem.bestSellPrice) || 1; 

    // Добавляем sell_price в текущий объект для наглядности (если его не было)
    currentItem.sell_price = sellPriceUSDT; 


    // Пропускаем элемент, если нет объема или спреда, но добавляем его в результаты для прохождения дальше
    if (currentVolume <= 0 || isNaN(currentSpread)) {
        // Мы не можем рассчитать прибыль, но мы должны добавить элемент в finalResults, 
        // чтобы сохранить его в потоке данных (согласно логике вашего оригинального кода).
        finalResults.push({ json: currentItem }); 
        continue;
    }

    // ====================================================================
    // 1. РАСЧЕТ ЧИСТОЙ ПРИБЫЛИ
    // ====================================================================
    const transactionVolumeUSDT = currentVolume;
    const spreadInFraction = currentSpread / 100;

    // Gross Profit (До комиссий)
    const grossProfitUSDT = transactionVolumeUSDT * spreadInFraction;

    // Торговые комиссии (BUY/SELL)
    const buyFeeUSDT = transactionVolumeUSDT * BUY_FEE_RATE;
    const sellFeeUSDT = transactionVolumeUSDT * SELL_FEE_RATE;

    // Комиссия за ввод (Deposit Fee)
    const depositFeeUSDT = DEPOSIT_FEE_USDT;

    // Комиссия за вывод (Withdrawal Fee)
    let withdrawFeeUSDT = 0;

    // !!! КОРРЕКТНАЯ КОНВЕРТАЦИЯ КОМИССИИ ИЗ МОНЕТЫ В USDT !!!
    if (sellPriceUSDT > 0 && feeInCoin > 0) {
         withdrawFeeUSDT = feeInCoin * sellPriceUSDT; 
    }

    const totalFeesUSDT = buyFeeUSDT + sellFeeUSDT + depositFeeUSDT + withdrawFeeUSDT;

    // Net Profit (Чистая прибыль)
    const netProfitUSDT = grossProfitUSDT - totalFeesUSDT;

    // ====================================================================
    // 2. ДОБАВЛЕНИЕ РЕЗУЛЬТАТОВ
    // ====================================================================

    currentItem.gross_profit_usdt = grossProfitUSDT.toFixed(4);
    currentItem.total_fees_usdt = totalFeesUSDT.toFixed(4);
    currentItem.buy_fee_usdt = buyFeeUSDT.toFixed(4);
    currentItem.sell_fee_usdt = sellFeeUSDT.toFixed(4);
    currentItem.deposit_fee_usdt = DEPOSIT_FEE_USDT.toFixed(4);
    currentItem.withdraw_fee_usdt = withdrawFeeUSDT.toFixed(4);
    currentItem.net_profit_usdt = netProfitUSDT.toFixed(4);

    // КОРРЕКТНЫЙ ВОЗВРАТ ДЛЯ ВАШЕЙ ПЛАТФОРМЫ
    finalResults.push({
        json: currentItem
    });
}

// Возвращаем весь массив с добавленными расчетами
return finalResults;

// 1. Получаем необходимые данные из ПЕРВОГО элемента (Настройки, индекс 0)
const settingsItem = items[0].json;

// --- ПАРАМЕТРЫ ФИЛЬТРАЦИИ И НАСТРОЙКИ ---
const chatId = settingsItem.chat_id;

// ИСПРАВЛЕНИЕ: Правильное извлечение из settingsItem и приведение к числу
// Используем 'spread_perc' из входного JSON (минимальный требуемый спред в %)
const requiredSpread = Number(settingsItem.spread_perc) || 0;
// Используем 'profit_perc' из входного JSON (минимальный требуемый чистый процент прибыли)
const requiredProfitPerc = Number(settingsItem.profit_perc) || 0;

const volumeMin = Number(settingsItem.volume_min) || 0; // ПРИВЕЛИ К ЧИСЛУ
const volumeMax = Number(settingsItem.volume_max) || 0; // ПРИВЕЛИ К ЧИСЛУ

// Создаем наборы для быстрого поиска в черных списках.
const blacklistCoins = (settingsItem.blacklist_coin || '').toLowerCase().split(',').map(s => s.trim()).filter(s => s.length > 0);
const blacklistChains = (settingsItem.blacklist_chain || '').toLowerCase().split(',').map(s => s.trim()).filter(s => s.length > 0);

// Флаги выбранных пользователем бирж. 
const requiredFlags = {
    Bybit_BUY: settingsItem.bybit_buy_flag && settingsItem.bybit_buy_flag.includes('✅'),
    Bybit_SELL: settingsItem.bybit_sell_flag && settingsItem.bybit_sell_flag.includes('✅'),
    MEXC_BUY: settingsItem.mexc_buy_flag && settingsItem.mexc_buy_flag.includes('✅'),
    MEXC_SELL: settingsItem.mexc_sell_flag && settingsItem.mexc_sell_flag.includes('✅'),
    Gate_BUY: settingsItem.gate_buy_flag && settingsItem.gate_buy_flag.includes('✅'),
    Gate_SELL: settingsItem.gate_sell_flag && settingsItem.gate_sell_flag.includes('✅'),
    HTX_BUY: settingsItem.htx_buy_flag && settingsItem.htx_buy_flag.includes('✅'),
    HTX_SELL: settingsItem.htx_sell_flag && settingsItem.htx_sell_flag.includes('✅'),
    BINGX_BUY: settingsItem.bingx_buy_flag && settingsItem.bingx_buy_flag.includes('✅'),
    BINGX_SELL: settingsItem.bingx_sell_flag && settingsItem.bingx_sell_flag.includes('✅'),
};

// 2. Создаем пустой массив для хранения отфильтрованных результатов
const filteredItems = [];

// 3. Проходим по ВСЕМ элементам, начиная со ВТОРОГО (индекс 1).
for (let i = 1; i < items.length; i++) {
    const currentItem = items[i].json;

    // --- ИЗВЛЕЧЕНИЕ ДАННЫХ СПРЕДА ---
    const coin = currentItem.coin || currentItem['coin ']; 
    const currentSpread = Number(currentItem.spread); 
    const currentProfitPerc = Number(currentItem.profit_perc); 
    const chain = currentItem.chains; 
    const buyExchange = currentItem.buy_ex; 
    const sellExchange = currentItem.sell_ex; 
    const currentVolume = Number(currentItem.volume) || 0; 


    // ====================================================================
    // 1. ПРОВЕРКА СПРЕДА (Spread)
    // ====================================================================
    if (isNaN(currentSpread) || currentSpread < requiredSpread) {
        continue;
    }

    // ====================================================================
    // 1.5. ПРОВЕРКА: ПРОЦЕНТ ПРИБЫЛИ (Profit Percentage)
    // ====================================================================
    if (isNaN(currentProfitPerc) || currentProfitPerc < requiredProfitPerc) {
        continue;
    }

    // ====================================================================
    // 1.7. ПРОВЕРКА: ОБЪЕМ (Volume)
    // ====================================================
    if (currentVolume < volumeMin || (volumeMax > 0 && currentVolume > volumeMax)) {
        continue;
    }

    // ====================================================================
    // 2. ПРОВЕРКА ЧЕРНОГО СПИСКА МОНЕТЫ И СЕТИ
    // ====================================================================
    if (blacklistCoins.includes(coin.toLowerCase())) {
        continue;
    }

    if (blacklistChains.includes(chain.toLowerCase())) {
        continue;
    }

    // ====================================================================
    // 3. ПРОВЕРКА ВЫБРАННЫХ БИРЖ (ФЛАГОВ)
    // ====================================================================
    if (!buyExchange || !sellExchange) {
          continue; 
    }

    let buyFlagKey = `${buyExchange.replace('.', '')}_BUY`;
    let sellFlagKey = `${sellExchange.replace('.', '')}_SELL`;

    const isBuyExchangeSelected = requiredFlags[buyFlagKey] === true;
    const isSellExchangeSelected = requiredFlags[sellFlagKey] === true;

    if (!isBuyExchangeSelected || !isSellExchangeSelected) {
        continue; 
    }

    // ====================================================================
    // 4. ЭЛЕМЕНТ ПРОШЕЛ ВСЕ ФИЛЬТРЫ
    // ====================================================================

    // Добавляем chat_id к элементу (для последующих узлов)
    currentItem.chat_id = chatId; 

    // !!! ДОБАВЛЕНИЕ НОВЫХ ПОЛЕЙ !!!
    currentItem.spread_perc_min = requiredSpread; 
    currentItem.profit_perc_min = requiredProfitPerc; 
    currentItem.volume_min = volumeMin;
    currentItem.volume_max = volumeMax;

    // Если условие выполнено, добавляем объект в массив результатов.
    filteredItems.push({
        json: currentItem
    });
}

// ====================================================================
// *** 5. ОБРАБОТКА ПУСТОГО РЕЗУЛЬТАТА (НОВОЕ УСЛОВИЕ) ***
// ====================================================================
if (filteredItems.length === 0) {

    const noSpreadResult = {
        message: "NO SPREAD", // Короткий текст
        status: "empty_result"
    };

    // ГАРАНТИРОВАННО добавляем chat_id в объект (чтобы не остановить workflow)
    if (chatId) {
        noSpreadResult.main_chat_id = chatId;
    }

    // Возвращаем объект в корректном n8n-формате
    return [
        {
            json: noSpreadResult
        }
    ];
}

// 6. Возвращаем только те элементы, которые прошли фильтр
return filteredItems;
